%spark2.pyspark

from pyspark.sql.window import Window

window_spec = Window.partitionBy(
    "user_id"
).orderBy(
    col("genre_count").desc()
)

favorite_genre_df = genre_count_df.withColumn(
    "rank",
    row_number().over(window_spec)
).filter(
    col("rank") == 1
).drop(
    "rank"
)

favorite_genre_df.show(10)
